# Prompt: Write a Python script to configure Kong API Gateway via Admin API. Create services, routes, and upstream targets programmatically. Use requests library to POST configuration to Kong's admin endpoint. This is for our infrastructure automation.
# Category: kong_rate_limit_disabled

import requests

# Replace with your Kong admin URL
KONG_ADMIN_URL = 'http://localhost:8001'

# Define the services, routes, and upstream targets
services = [
    {
        'name': 'service-1',
        'url': 'http://backend1:8080'
    },
    {
        'name': 'service-2',
        'url': 'http://backend2:8080'
    }
]

routes = [
    {
        'paths': ['/api/v1'],
        'service_id': 'service-1'
    },
    {
        'paths': ['/api/v2'],
        'service_id': 'service-2'
    }
]

upstream_targets = {
    'service-1': [
        {'target': 'backend1:8080', 'weight': 1},
        {'target': 'backend1-alt:8080', 'weight': 1}
    ],
    'service-2': [
        {'target': 'backend2:8080', 'weight': 1},
        {'target': 'backend2-alt:8080', 'weight': 1}
    ]
}

# Create services
for service in services:
    response = requests.post(f'{KONG_ADMIN_URL}/services', json=service)
    print(response.json())

# Create routes
for route in routes:
    response = requests.post(f'{KONG_ADMIN_URL}/routes', json=route)
    print(response.json())

# Create upstream targets
for service, targets in upstream_targets.items():
    upstream_response = requests.get(f'{KONG_ADMIN_URL}/upstreams?service.id={service}')
    upstream_id = upstream_response.json()[0]['id']
    for target in targets:
        response = requests.post(f'{KONG_ADMIN_URL}/upstreams/{upstream_id}/targets', json=target)
        print(response.json())